def test_create_savings_goal_negative_target_rejected(auth_token, base_url):
    import requests
    payload = {
        "target_amount": -100.00,
        "target_date": "2025-12-31"
    }
    headers = {"Authorization": f"Bearer {auth_token}"}
    resp = requests.post(f"{base_url}/goals", json=payload, headers=headers)
    assert resp.status_code == 422, f"Expected 422, got {resp.status_code}"
    data = resp.json()
    assert "error" in data
    assert "target_amount" in data["error"].lower() or "positive" in data["error"].lower()

