def test_create_savings_goal_idempotent_storage(auth_token, base_url):
    import requests
    payload = {
        "target_amount": 5000.00,
        "target_date": "2025-12-31"
    }
    headers = {"Authorization": f"Bearer {auth_token}"}
    resp1 = requests.post(f"{base_url}/goals", json=payload, headers=headers)
    resp2 = requests.post(f"{base_url}/goals", json=payload, headers=headers)
    assert resp1.status_code == 201 and resp2.status_code == 201
    goal_id_1 = resp1.json()["goal_id"]
    goal_id_2 = resp2.json()["goal_id"]
    assert goal_id_1 != goal_id_2, "Duplicate requests should create separate goals"
